CREATE VIEW `ads_edit_book_RemunerationDetail_view` (`dt` COMMENT "createtime 分区", `Productid` COMMENT "产品id", `Id` COMMENT "自增id", `AuthorId` COMMENT "作者id", `RoleType` COMMENT "角色类型1：译员、2：外籍一校、3：二校、4：三校、5：PM、6：初译审核、7：初校审核、8：国内测试稿审核、9：国外测试稿审核、10：三校抽查、11：一校抽查、12：质检抽查", `UnitPrice` COMMENT "单价", `ChapterId` COMMENT "章节id", `bookId` COMMENT "书籍ID", `bookName` COMMENT "书籍名称", `CreateTime` COMMENT "创建时间", `ToLanguage` COMMENT "目标书籍语言", `FontLength` COMMENT "字数", `CurrencyType` COMMENT "货币类型 1：人民币 2：美元", `UndoReason` COMMENT "撤销原因") AS SELECT `ods`.`a`.`dt`, `ods`.`a`.`Productid`, `ods`.`a`.`Id`, `ods`.`a`.`AuthorId`, `ods`.`a`.`RoleType`, `ods`.`a`.`UnitPrice`, `ods`.`a`.`ChapterId`, `ods`.`a`.`bookId`, `ods`.`c`.`BookName`, `ods`.`a`.`CreateTime`, `ods`.`a`.`ToLanguage`, `ods`.`a`.`FontLength`, `ods`.`a`.`CurrencyType`, `ods`.`a`.`UndoReason`
FROM `ods`.`ods_edit_book_RemunerationDetail` AS `a` LEFT OUTER JOIN `ods`.`ods_tidb_shuangwen_en_objectbook` AS `c` ON (((`ods`.`a`.`productid` = `ods`.`c`.`productid`) AND (`ods`.`a`.`bookId` = `ods`.`c`.`SwBookId`)) AND (`ods`.`a`.`ToLanguage` = `ods`.`c`.`ToLanguage`)) AND (`ods`.`c`.`Status` = 1);